import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input containing path traversal

        String basePath = "/var/www/html/images/"; // Base directory where images are stored
        String normalizedInput = new File(basePath, userInput).getCanonicalPath(); // Normalize user input against base path

        if (!normalizedInput.startsWith(basePath)) {
            System.err.println("Invalid file path specified.");
            return;
        }

        try {
            File imageFile = new File(normalizedInput);
            byte[] imageBytes = Files.readAllBytes(Paths.get(imageFile.getAbsolutePath()));
            System.out.println("Image loaded successfully.");
        } catch (IOException e) {
            System.err.println("Failed to load image: " + e.getMessage());
        }
    }
}

